let fallback_{{sanitizedId}} = {{props.fallbackValue}};
let {{outputVar}} = fallback_{{sanitizedId}};
let valid_{{sanitizedId}} = false;
let jsonInput_{{sanitizedId}} = {{inputs.json}};
if (jsonInput_{{sanitizedId}} == null) { jsonInput_{{sanitizedId}} = '{}'; }
try {
  parsed_{{sanitizedId}} = JSON.parse(jsonInput_{{sanitizedId}});
  valid_{{sanitizedId}} = true;
