    extractPath_{{sanitizedId}} = {{props.defaultPath}};
  }
  if (extractPath_{{sanitizedId}} != null && extractPath_{{sanitizedId}} != '') {
    let keys_{{sanitizedId}} = extractPath_{{sanitizedId}}.split('.');
    let current_{{sanitizedId}} = parsed_{{sanitizedId}};
    let i_{{sanitizedId}} = 0;
    while (i_{{sanitizedId}} < keys_{{sanitizedId}}.length && current_{{sanitizedId}} != null) {
      current_{{sanitizedId}} = current_{{sanitizedId}}[keys_{{sanitizedId}}[i_{{sanitizedId}}]];
      i_{{sanitizedId}} = i_{{sanitizedId}} + 1;
    }
    if (current_{{sanitizedId}} != null) {
      {{outputVar}} = current_{{sanitizedId}};
    }
  } else {
    {{outputVar}} = parsed_{{sanitizedId}};
  }
} catch (e) {
  console.warn('JSON parse error: ' + e.message);
}
